// Get all items from the Google Sheet
// Sheet has headers: Title (col A), Status (col B)
const items = $input.all();

if (!items || items.length === 0) {
  return [{ json: { error: 'No topics found in sheet', postReady: false } }];
}

// Find the FIRST row where Status is NOT 'Done'
for (let i = 0; i < items.length; i++) {
  const item = items[i].json;

  // DIRECTLY read the Title column (header is 'Title')
  const title = item.Title || item.title || '';

  // Read the Status column
  const status = (item.Status || item.status || '').toString().trim().toLowerCase();

  // Skip if already processed
  if (status === 'done' || status === 'published' || status === 'completed') {
    continue;
  }

  // Skip if title is empty
  if (!title || title.trim() === '') {
    continue;
  }

  // Found a pending topic!
  const rowNum = item.row_number || (i + 2);
  return [{
    json: {
      Topic: title.trim(),
      Keyword: title.trim(),
      Category: 'Fertility',
      Tags: '',
      'Target Audience': 'women seeking fertility information',
      rowNumber: rowNum,
      postReady: true
    }
  }];
}

return [{ json: { error: 'All topics have been processed!', postReady: false } }];

const item = $input.item.json;
const topicData = $('Get First Pending').item.json;
const rowId = topicData.rowNumber;
const topic = topicData.Topic || '';
const keyword = topicData.Keyword || topic;

// Check if Gemini errored
if (!item.output && !item.text && !item.response) {
  return { json: { rowId, topic, error: 'Gemini returned no output', postReady: false } };
}

// Get raw text
let raw = item.output || item.text || '';
if (!raw && item.response) raw = item.response.text || JSON.stringify(item.response);
if (!raw) raw = JSON.stringify(item);

// Strip markdown fences
raw = raw.replace(/```json\n?/gi, '').replace(/```\n?/g, '').trim();

// Extract JSON block
const jsonMatch = raw.match(/\{[\s\S]*\}/);
if (!jsonMatch) {
  return { json: { rowId, topic, error: 'No JSON found in Gemini output', postReady: false } };
}
let jsonStr = jsonMatch[0];

let blog;
try { blog = JSON.parse(jsonStr); } catch(e1) {
  try {
    let s = jsonStr;
    s = s.replace(/([^\\])\n/g, '$1\\n').replace(/([^\\])\r/g, '$1').replace(/([^\\])\t/g, '$1\\t');
    blog = JSON.parse(s);
  } catch(e2) {
    function extractField(src, key) {
      const re = new RegExp('"' + key + '"\\s*:\\s*"([\\s\\S]*?)"\\s*(?:,\\s*"[a-z_]|\\}$)', 'i');
      const m = src.match(re);
      return m ? m[1] : '';
    }
    function extractArray(src, key) {
      const re = new RegExp('"' + key + '"\\s*:\\s*\\[([\\s\\S]*?)\\]', 'i');
      const m = src.match(re);
      if (!m) return [];
      return m[1].match(/"([^"]*)"/g)?.map(x => x.replace(/"/g, '')) || [];
    }
    const title = extractField(jsonStr, 'title');
    const contentHtml = extractField(jsonStr, 'content_html');
    if (!title || !contentHtml) {
      return { json: { rowId, topic, error: 'JSON parse failed: ' + e2.message, postReady: false } };
    }
    blog = {
      title, content_html: contentHtml,
      slug: extractField(jsonStr, 'slug') || title.toLowerCase().replace(/[^a-z0-9\s-]/g, '').replace(/\s+/g, '-'),
      excerpt: extractField(jsonStr, 'excerpt'),
      meta_title: extractField(jsonStr, 'meta_title') || title,
      meta_description: extractField(jsonStr, 'meta_description'),
      focus_keyword: extractField(jsonStr, 'focus_keyword'),
      category: extractField(jsonStr, 'category') || 'General',
      tags: extractArray(jsonStr, 'tags')
    };
  }
}

if (!blog || !blog.title || !blog.content_html) {
  return { json: { rowId, topic, error: 'Missing title or content', postReady: false } };
}

// Clean up slug: must be English letters/numbers only.
let slug = (blog.slug || '').toLowerCase().replace(/[^a-z0-9\s-]/g, '').replace(/\s+/g, '-');
if (!slug) {
  slug = topic.toLowerCase().replace(/[^a-z0-9\s-]/g, '').replace(/\s+/g, '-');
  if (typeof language !== 'undefined' && language !== 'English') {
    slug += '-in-' + language.toLowerCase();
  }
}
slug = slug.substring(0, 80);

// NO image in blog body content - image will be set as Featured Image only
const cleanedContent = (blog.content_html || '').replace(/\\n/g, '').replace(/\n/g, '');
const tags = Array.isArray(blog.tags) ? blog.tags : (blog.tags || '').split(',').map(t => t.trim()).filter(Boolean);

// SMART TRUNCATION
function truncateStr(str, maxLen) {
  if (!str) return '';
  if (str.length <= maxLen) return str;
  let t = str.substring(0, maxLen);
  let lastSpace = t.lastIndexOf(' ');
  if (lastSpace > 0) t = t.substring(0, lastSpace);
  return t.replace(/[^a-zA-Z0-9]$/, '');
}

const finalMetaTitle = truncateStr(blog.meta_title || blog.title, 60);
const finalMetaDesc = truncateStr(blog.meta_description || blog.excerpt || '', 160);

// Category filter and default category addition
const ALLOWED_CATEGORIES = [
  "Best Practices And FAQs",
  "Fertility Hospitals",
  "Menstrual Health",
  "Fertility Treatments",
  "Male Infertility Doctor",
  "Medical Innovations",
  "PCOS Treatment",
  "Pregnancy Care"
];

const titleLower = (blog.title || topic || '').toLowerCase();
const matchedCats = new Set();

// Always include Best Practices And FAQs by default
matchedCats.add("Best Practices And FAQs");

// Keyword mapping:
if (/\bpcos\b|\bpcod\b|polycystic|ovarian syndrome/i.test(titleLower)) {
  matchedCats.add("PCOS Treatment");
}

if (/\bmale\b|\bsperm\b|\bsemen\b|varicocele|testicular|\bmen\b|\bman\b/i.test(titleLower) && !/\bfemale\b|\bwomen\b/i.test(titleLower)) {
  matchedCats.add("Male Infertility Doctor");
}

if (/menstrual|period|periods|cycle|menstruation|ovulation|bleeding|fsh|lh|estrogen|progesterone|hormone|hormonal/i.test(titleLower)) {
  matchedCats.add("Menstrual Health");
}

if (/treatment|treatments|ivf|icsi|iui|surrogacy|clomid|egg freezing|fertility therapy|acupuncture|donor|in vitro|fertilization/i.test(titleLower)) {
  matchedCats.add("Fertility Treatments");
}

if (/hospital|hospitals|clinic|clinics|center|centres|arc|chennai|bangalore|coimbatore|madurai|trichy|vellore|salem/i.test(titleLower)) {
  matchedCats.add("Fertility Hospitals");
}

if (/innovation|innovations|technology|latest|advanced|research|new method|stem cell|prp|laser assisted|pgd|pgs|era test/i.test(titleLower)) {
  matchedCats.add("Medical Innovations");
}

if (/pregnancy|pregnant|prenatal|mother|motherhood|baby|conceive|conceiving|miscarriage|gestational|conception/i.test(titleLower)) {
  matchedCats.add("Pregnancy Care");
}

// Now merge with OpenAI/Gemini's selected categories
let aiCats = [];
if (Array.isArray(blog.categories)) {
  aiCats = blog.categories;
} else if (typeof blog.categories === 'string') {
  aiCats = [blog.categories];
} else if (typeof blog.category === 'string') {
  aiCats = [blog.category];
}

aiCats.forEach(cat => {
  if (ALLOWED_CATEGORIES.includes(cat)) {
    matchedCats.add(cat);
  }
});

const selectedCats = Array.from(matchedCats);

return {
  json: {
    rowId, title: blog.title, slug, content: cleanedContent,
    excerpt: blog.excerpt || blog.meta_description || '',
    meta_title: finalMetaTitle,
    meta_description: finalMetaDesc,
    focus_keyword: blog.focus_keyword || keyword,
    tags: tags.join(', '), category: blog.category || 'General',
    categories: selectedCats,
    postReady: true
  }
};

// ===== RESOLVE FEATURED IMAGE, CATEGORIES & TAGS FROM WORDPRESS =====
// The image URL is already uploaded to WP Media Library.
// We need to find its Media ID so we can set it as Featured Image.
// We also resolve category names to their WordPress IDs (no creation allowed).
// And we resolve or dynamically create tags (creation allowed).
// =====================================================================

const WP_URL = 'https://forallhealthcare.com'; // No trailing slash
const WP_USER = 'YOUR_WP_USERNAME';
const WP_APP_PASSWORD = 'YOUR_WP_APP_PASSWORD';

// The image URL in the WordPress media library
const FEATURED_IMAGE_URL = 'https://forallhealthcare.com/wp-content/uploads/2026/05/egg-and-sperm-collection.webp';

const blogData = $input.item.json || {};
let featuredMediaId = 0;
const categoryIds = [];
const tagIds = [];

try {
  const authHeader = 'Basic ' + Buffer.from(WP_USER + ':' + WP_APP_PASSWORD).toString('base64');

  // 1. RESOLVE FEATURED IMAGE
  try {
    const filename = FEATURED_IMAGE_URL.split('/').pop().replace(/\.[^.]+$/, '');
    const searchUrl = WP_URL + '/wp-json/wp/v2/media?search=' + encodeURIComponent(filename) + '&per_page=10';

    let mediaItems;
    if (typeof fetch !== 'undefined') {
      const r = await fetch(searchUrl, { headers: { 'Authorization': authHeader } });
      mediaItems = await r.json();
    } else {
      mediaItems = await this.helpers.httpRequest({
        method: 'GET',
        url: searchUrl,
        headers: { 'Authorization': authHeader },
        json: true
      });
    }

    if (mediaItems && Array.isArray(mediaItems) && mediaItems.length > 0) {
      const exactMatch = mediaItems.find(m => m.source_url === FEATURED_IMAGE_URL);
      featuredMediaId = exactMatch ? exactMatch.id : mediaItems[0].id;
    }
  } catch (err) {}

  // 2. RESOLVE CATEGORIES
  const catNames = blogData.categories || ["Best Practices And FAQs"];
  for (const name of catNames) {
    try {
      const searchUrl = WP_URL + '/wp-json/wp/v2/categories?search=' + encodeURIComponent(name);
      let catRes;
      if (typeof fetch !== 'undefined') {
        const r = await fetch(searchUrl, { headers: { 'Authorization': authHeader } });
        catRes = await r.json();
      } else {
        catRes = await this.helpers.httpRequest({
          method: 'GET',
          url: searchUrl,
          headers: { 'Authorization': authHeader },
          json: true
        });
      }

      let matchedId = null;
      if (catRes && Array.isArray(catRes)) {
        const match = catRes.find(c => c.name.toLowerCase() === name.toLowerCase());
        if (match) matchedId = match.id;
      }

      // DO NOT permit creating new categories if missing. 
      // Only attach if matchedId is resolved from existing WP categories.
      if (matchedId) {
        categoryIds.push(matchedId);
      }
    } catch (catErr) {}
  }

  // 3. RESOLVE & CREATE TAGS
  // blogData.tags is a comma-separated string: "low AMH, female infertility..."
  const tagNames = (blogData.tags || '').split(',').map(t => t.trim()).filter(Boolean);
  for (const name of tagNames) {
    try {
      const searchUrl = WP_URL + '/wp-json/wp/v2/tags?search=' + encodeURIComponent(name);
      let tagsRes;
      if (typeof fetch !== 'undefined') {
        const r = await fetch(searchUrl, { headers: { 'Authorization': authHeader } });
        tagsRes = await r.json();
      } else {
        tagsRes = await this.helpers.httpRequest({
          method: 'GET',
          url: searchUrl,
          headers: { 'Authorization': authHeader },
          json: true
        });
      }

      let matchedId = null;
      if (tagsRes && Array.isArray(tagsRes)) {
        const match = tagsRes.find(t => t.name.toLowerCase() === name.toLowerCase());
        if (match) matchedId = match.id;
      }

      if (matchedId) {
        tagIds.push(matchedId);
      } else {
        // Tag doesn't exist, let's create it
        const createUrl = WP_URL + '/wp-json/wp/v2/tags';
        let createRes;
        if (typeof fetch !== 'undefined') {
          const r = await fetch(createUrl, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json', 'Authorization': authHeader },
            body: JSON.stringify({ name })
          });
          createRes = await r.json();
        } else {
          createRes = await this.helpers.httpRequest({
            method: 'POST',
            url: createUrl,
            headers: { 'Content-Type': 'application/json', 'Authorization': authHeader },
            body: { name },
            json: true,
            failOnStatusCode: false
          });
        }

        if (createRes && createRes.id) {
          tagIds.push(createRes.id);
        } else if (createRes && createRes.code === 'term_exists') {
          const termId = createRes.data?.term_id;
          if (termId) tagIds.push(termId);
        }
      }
    } catch (tagErr) {
      let errorBody = null;
      if (tagErr.description) {
        try { errorBody = JSON.parse(tagErr.description); } catch (e) {}
      } else if (tagErr.response?.data) {
        errorBody = tagErr.response.data;
      } else if (tagErr.message) {
        const jsonMatch = tagErr.message.match(/\{[\s\S]*\}/);
        if (jsonMatch) {
          try { errorBody = JSON.parse(jsonMatch[0]); } catch (e) {}
        }
      }
      if (errorBody && errorBody.code === 'term_exists') {
        const termId = errorBody.data?.term_id;
        if (termId) tagIds.push(termId);
      }
    }
  }
} catch (err) {}

// Pass through all blog data + the resolved media ID, category IDs, and tag IDs
return {
  json: {
    ...blogData,
    featuredMediaId: featuredMediaId,
    featuredImageUrl: FEATURED_IMAGE_URL,
    categoryIds: categoryIds,
    tagIds: tagIds
  }
};

// ===== WORDPRESS CREDENTIALS =====
const WP_URL = 'https://forallhealthcare.com'; // No trailing slash
const WP_USER = 'YOUR_WP_USERNAME';
const WP_APP_PASSWORD = 'YOUR_WP_APP_PASSWORD';
// ==================================

const blogData = $('Parse Blog JSON').item?.json || $('Parse Blog JSON1').item?.json || $node['Parse Blog JSON'].json;
const topicData = $('Get First Pending').item?.json || $('Get First Pending1').item?.json || $node['Get First Pending'].json;
const featuredData = $('Resolve Featured Image').item?.json || $('Resolve Featured Image1').item?.json || $node['Resolve Featured Image'].json;

const rowId = blogData.rowId;
const originalTitle = topicData.OriginalTitle || topicData.Topic || blogData.title;
const wpResult = $input.item.json;
const postId = wpResult.id;
const posted = !!(postId && typeof postId === 'number');

let debugLog = [];

if (posted) {
  const authHeader = 'Basic ' + Buffer.from(WP_USER + ':' + WP_APP_PASSWORD).toString('base64');
  const headers = { 
    'Content-Type': 'application/json', 
    'Authorization': authHeader,
    'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) n8n/1.0'
  };

  // 1. UPDATE RANKMATH SEO META
  try {
    await this.helpers.httpRequest({
      method: 'POST',
      url: WP_URL + '/wp-json/rankmath/v1/updateMeta',
      headers: headers,
      body: {
        objectType: 'post',
        objectID: postId,
        meta: {
          rank_math_title: blogData.meta_title || blogData.title,
          rank_math_description: blogData.meta_description || blogData.excerpt || '',
          rank_math_focus_keyword: blogData.focus_keyword || '',
          rank_math_robots: 'index,follow'
        }
      },
      json: true
    });
    debugLog.push('RankMath Update: Success');
  } catch(e) {
    debugLog.push('RankMath Error: ' + e.message);
  }

  // 2. ATTACH FEATURED IMAGE, CATEGORIES & TAGS
  try {
    const updateBody = {
      meta: {
        rank_math_title: blogData.meta_title || blogData.title,
        rank_math_description: blogData.meta_description || blogData.excerpt || '',
        rank_math_focus_keyword: blogData.focus_keyword || ''
      }
    };

    if (featuredData && featuredData.featuredMediaId && featuredData.featuredMediaId > 0) {
      updateBody.featured_media = featuredData.featuredMediaId;
    }

    // Attach category IDs resolved from WP
    if (featuredData && featuredData.categoryIds && featuredData.categoryIds.length > 0) {
      updateBody.categories = featuredData.categoryIds;
    } else if (blogData.categoryIds && blogData.categoryIds.length > 0) {
      updateBody.categories = blogData.categoryIds;
    }

    // Attach tag IDs resolved from WP
    if (featuredData && featuredData.tagIds && featuredData.tagIds.length > 0) {
      updateBody.tags = featuredData.tagIds;
    } else if (blogData.tagIds && blogData.tagIds.length > 0) {
      updateBody.tags = blogData.tagIds;
    }

    await this.helpers.httpRequest({
      method: 'POST',
      url: WP_URL + '/wp-json/wp/v2/posts/' + postId,
      headers: headers,
      body: updateBody,
      json: true
    });
    debugLog.push('WP Standard Post Update: Success');
  } catch(e) {
    debugLog.push('Standard Post Update Error: ' + e.message);
  }
}

return { json: { rowId, Title: originalTitle, status: posted ? 'published' : 'wp_error', wpId: postId || null, debugLog } };
